import{_ as a,o as e,c as o,a2 as r}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"1970年 核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1970年/核心总结.md","filePath":"01_letters/1970年/核心总结.md"}'),d={name:"01_letters/1970年/核心总结.md"};function n(l,t,s,h,i,u){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="_1970年-核心总结" tabindex="-1">1970年 核心总结 <a class="header-anchor" href="#_1970年-核心总结" aria-label="Permalink to &quot;1970年 核心总结&quot;">​</a></h1><blockquote><p><strong>一句话总结：</strong> 银行业务创下历史新高，保险规模扩张但承保利润下滑，纺织业务逆风求生。伯克希尔正式从单一纺织厂，转型为多元控股平台。</p></blockquote><h2 id="核心数据" tabindex="-1">核心数据 <a class="header-anchor" href="#核心数据" aria-label="Permalink to &quot;核心数据&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>1970年</th><th>对比</th></tr></thead><tbody><tr><td>营业利润</td><td>~430万美元</td><td></td></tr><tr><td>股东权益回报率</td><td>~10%</td><td>处于历史较低水平</td></tr><tr><td>纺织业务</td><td>盈亏平衡</td><td>苦苦挣扎</td></tr><tr><td>银行业务</td><td>创历史新高</td><td>顶级ROA</td></tr></tbody></table><h2 id="三个业务板块的真实状态" tabindex="-1">三个业务板块的真实状态 <a class="header-anchor" href="#三个业务板块的真实状态" aria-label="Permalink to &quot;三个业务板块的真实状态&quot;">​</a></h2><p><strong>① 银行业务——最耀眼的星</strong></p><p>伊利诺伊国民银行的 Gene Abegg 是真正的明星管理人。在存款规模持平、没有借款的情况下，税后净经营收益率远超行业均值的2%。银行没有新增资本，从1931年创办至今仅用25万美元起步。巴菲特称之为&quot;全美盈利能力最强的银行之一&quot;。</p><p><strong>② 保险业务——规模扩张、利润下滑</strong></p><p>Jack Ringwalt 和 Phil Liesche 管理的传统保险业务保费规模大幅增长，但综合损失与费用率达到约100%，即承保盈亏平衡。</p><p>两个值得关注的动向：</p><ul><li><strong>再保险部门</strong>起步：由 George Young 负责，再保险是&quot;放大器&quot;——保费规模大、资金滞留时间长，是浮存金的核心来源</li><li><strong>本土州模式</strong>启动：内布拉斯加意外保险公司（HomeState）成立，提出&quot;大公司服务能力+小公司本地触达&quot;的差异化策略</li></ul><p><strong>③ 纺织业务——逆风中的坚持</strong></p><p>男士服装衬里和家居面料销售额大幅下滑，但 Ken Chace 团队的努力让业务仅以盈亏平衡收场。巴菲特特意在年报中称赞他们的敬业精神——&quot;毫不逊色于公司旗下盈利高得多的业务板块&quot;。</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><p><strong>洞察一：多元化资本配置战略已见成效</strong></p><p>1965年管理层接手时，公司全部资源压在纺织业务。如今纺织仅贡献微薄利润，而银行和保险已接管盈利主力。这是伯克希尔基因重塑的第三年，也是证明&quot;资本重新配置&quot;可行性的关键节点。</p><p><strong>洞察二：保险规模扩张是为了浮存金</strong></p><p>保费规模大幅增长的背后，是传统市场承保能力收紧。这不是主动的承保决策，而是市场周期性机会带来的资金流入。对伯克希尔而言，承保利润是次要的，浮存金规模才是核心目标。</p><p><strong>洞察三：银行是真正的现金机器</strong></p><p>银行不需要外部资本，却持续创造超额回报。伊利诺伊国民银行1931年以25万美元创办，到1970年已是当地最大银行。这种&quot;无本万利&quot;的特性，在未来多年将持续为巴菲特提供优质资本来源。</p><h2 id="名言" tabindex="-1">名言 <a class="header-anchor" href="#名言" aria-label="Permalink to &quot;名言&quot;">​</a></h2><blockquote><p>&quot;银行控股公司新立法出台后，我们有约十年时间处置所持银行股权。但目前我们不会做出决定。&quot; ——沃伦·巴菲特，1970年年报</p></blockquote><p>（解读：1970年银行控股公司法给了十年宽限期，巴菲特选择等待，直到1978年才最终剥离银行业务。这个&quot;等等看&quot;的耐心，正是伯克希尔文化的早期体现。）</p><h2 id="重要人事" tabindex="-1">重要人事 <a class="header-anchor" href="#重要人事" aria-label="Permalink to &quot;重要人事&quot;">​</a></h2><table tabindex="0"><thead><tr><th>人物</th><th>角色</th><th>亮点</th></tr></thead><tbody><tr><td>Gene Abegg</td><td>银行 CEO</td><td>1931年创办，持续创造顶级回报</td></tr><tr><td>Jack Ringwalt</td><td>国民赔偿保险 CEO</td><td>保险业务扩张的核心推动者</td></tr><tr><td>Phil Liesche</td><td>保险管理人</td><td>承保纪律坚守者</td></tr><tr><td>George Young</td><td>再保险负责人</td><td>新业务开拓者</td></tr><tr><td>Ken Chace</td><td>纺织业务负责人</td><td>逆风中坚持的管理人</td></tr></tbody></table><h2 id="历史坐标" tabindex="-1">历史坐标 <a class="header-anchor" href="#历史坐标" aria-label="Permalink to &quot;历史坐标&quot;">​</a></h2><p><strong>在巴菲特投资生涯中的位置：</strong></p><ul><li>距离1956年巴菲特合伙基金成立：<strong>14年</strong></li><li>距离1965年正式接手伯克希尔：<strong>5年</strong></li><li>伯克希尔仍处于&quot;困境转型期&quot;，距离1972年的历史性高点还有2年</li></ul>',28)])])}const q=a(d,[["render",n]]);export{c as __pageData,q as default};
